def generate_certificates():
    """Generate self-signed certificates for development/testing."""
    os.makedirs("certs", exist_ok=True)

    cert_file = IDP_CONFIG["certificate_file"]
    key_file = IDP_CONFIG["private_key_file"]
    ssl_cert_file = IDP_CONFIG["ssl_cert_file"]
    ssl_key_file = IDP_CONFIG["ssl_key_file"]

    if not os.path.exists(key_file) or not os.path.exists(cert_file):
        print("Generating IdP signing certificates...")
        os.system(
            f'openssl req -x509 -newkey rsa:2048 -keyout {key_file} -out {cert_file} '
            f'-days 365 -nodes -subj "/CN=idp.internal.example.com/O=Internal IdP"'
        )

    if not os.path.exists(ssl_key_file) or not os.path.exists(ssl_cert_file):
        print("Generating HTTPS server certificates...")
        os.system(
            f'openssl req -x509 -newkey rsa:2048 -keyout {ssl_key_file} -out {ssl_cert_file} '
            f'-days 365 -nodes -subj "/CN=idp.internal.example.com/O=Internal IdP"'
        )


def load_certificate():
    """Load the IdP certificate."""
    with open(IDP_CONFIG["certificate_file"], "r") as f:
        cert = f.read()
    # Strip PEM headers for inclusion in SAML metadata
    cert_clean = cert.replace("-----BEGIN CERTIFICATE-----", "").replace(
        "-----END CERTIFICATE-----", ""
    ).replace("\n", "").strip()
    return cert, cert_clean


def load_private_key():
    """Load the IdP private key."""
    with open(IDP_CONFIG["private_key_file"], "r") as f:
        return f.read()


def authenticate_user(username, password):
    """Authenticate user against the user store."""
    user = USER_STORE.get(username)
    if user and user["password"] == password:
        return user["attributes"]
    return None


def create_session(username, attributes):
    """Create a session for the authenticated user."""
    session_id = "_" + uuid.uuid4().hex
    SESSIONS[session_id] = {
        "username": username,
        "attributes": attributes,
        "created_at": datetime.now(timezone.utc),
        "expires_at": datetime.now(timezone.utc)
        + timedelta(minutes=IDP_CONFIG["session_lifetime_minutes"]),
    }
    return session_id


def get_session(session_id):
    """Retrieve and validate a session."""
    if not session_id:
        return None
    session = SESSIONS.get(session_id)
    if session and session["expires_at"] > datetime.now(timezone.utc):
        return session
    if session:
        del SESSIONS[session_id]
    return None


def destroy_session(session_id):
    """Destroy a session."""
    if session_id in SESSIONS:
        del SESSIONS[session_id]


def build_saml_response(
    sp_entity_id,
    acs_url,
    user_attributes,
    authn_request_id=None,
):
    """
    Build a signed SAML Response with a signed Assertion.

    The assertion is signed but NOT encrypted. Transport security (HTTPS)
    is relied upon for confidentiality of the assertion content.
    """
    now = datetime.now(timezone.utc)
    not_on_or_after = now + timedelta(minutes=IDP_CONFIG["assertion_lifetime_minutes"])
    response_id = "_" + uuid.uuid4().hex
    assertion_id = "_" + uuid.uuid4().hex
    session_index = "_" + uuid.uuid4().hex

    now_str = now.strftime("%Y-%m-%dT%H:%M:%SZ")
    not_on_or_after_str = not_on_or_after.strftime("%Y-%m-%dT%H:%M:%SZ")
    not_before_str = (now - timedelta(seconds=30)).strftime("%Y-%m-%dT%H:%M:%SZ")

    name_id = user_attributes.get("email", user_attributes.get("uid", "unknown"))

    # Build the SAML Response XML
    response_xml = f"""<samlp:Response
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{response_id}"
    Version="2.0"
    IssueInstant="{now_str}"
    Destination="{acs_url}"
    {f'InResponseTo="{authn_request_id}"' if authn_request_id else ''}>
    <saml:Issuer>{IDP_CONFIG["entity_id"]}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
    <saml:Assertion
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{assertion_id}"
        Version="2.0"
        IssueInstant="{now_str}">
        <saml:Issuer>{IDP_CONFIG["entity_id"]}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
                SPNameQualifier="{sp_entity_id}">{name_id}</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData
                    {f'InResponseTo="{authn_request_id}"' if authn_request_id else ''}
                    NotOnOrAfter="{not_on_or_after_str}"
                    Recipient="{acs_url}"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before_str}" NotOnOrAfter="{not_on_or_after_str}">
            <saml:AudienceRestriction>
                <saml:Audience>{sp_entity_id}</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{now_str}" SessionIndex="{session_index}"
            SessionNotOnOrAfter="{not_on_or_after_str}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>"""

    # Add user attributes
    for attr_name, attr_value in user_attributes.items():
        response_xml += f"""
            <saml:Attribute Name="{attr_name}"
                NameFormat="urn:oasis:names:tc:SAML:2.0:attrname-format:basic">
                <saml:AttributeValue xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
                    xsi:type="xs:string">{attr_value}</saml:AttributeValue>
            </saml:Attribute>"""

    response_xml += """
        </saml:AttributeStatement>
    </saml:Assertion>
</samlp:Response>"""

    # Parse the XML
    root = etree.fromstring(response_xml.encode("utf-8"))

    # Sign the assertion
    assertion = root.find(".//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion")
    signed_assertion = sign_xml_element(assertion, assertion_id)

    # Replace the unsigned assertion with the signed one
    root.remove(assertion)
    status = root.find(".//{urn:oasis:names:tc:SAML:2.0:protocol}Status")
    status.addnext(signed_assertion)

    # Sign the response itself
    signed_root = sign_xml_element(root, response_id)

    return etree.tostring(signed_root, xml_declaration=False, encoding="unicode")


def sign_xml_element(element, element_id):
    """
    Sign an XML element using XML Digital Signature (xmldsig).

    Uses RSA-SHA256 for the signature algorithm and SHA256 for the digest,
    with exclusive canonicalization (exc-c14n).
    """
    private_key = load_private_key()
    cert_pem, _ = load_certificate()

    # Create signature template
    signature_node = xmlsec.template.create(
        element,
        c14n_method=xmlsec.constants.TransformExclC14N,
        sign_method=xmlsec.constants.TransformRsaSha256,
        ns="ds",
    )

    # Insert signature after Issuer element (SAML standard placement)
    issuer = element.find("{urn:oasis:names:tc:SAML:2.0:assertion}Issuer")
    if issuer is None:
        issuer = element.find("{urn:oasis:names:tc:SAML:2.0:protocol}Issuer")

    if issuer is not None:
        issuer.addnext(signature_node)
    else:
        element.insert(0, signature_node)

    # Add reference
    ref = xmlsec.template.add_reference(
        signature_node,
        xmlsec.constants.TransformSha256,
        uri="#" + element_id,
    )
    xmlsec.template.add_transform(ref, xmlsec.constants.TransformEnveloped)
    xmlsec.template.add_transform(ref, xmlsec.constants.TransformExclC14N)

    # Add key info
    key_info = xmlsec.template.ensure_key_info(signature_node)
    x509_data = xmlsec.template.add_x509_data(key_info)
    xmlsec.template.x509_data_add_certificate(x509_data)

    # Load private key and certificate
    ctx = xmlsec.SignatureContext()
    key = xmlsec.Key.from_memory(private_key, xmlsec.constants.KeyDataFormatPem)
    key.load_cert(cert_pem, xmlsec.constants.KeyDataFormatPem)
    ctx.key = key

    # Sign
    ctx.sign(signature_node)

    return element


def parse_authn_request(saml_request_b64):
    """Parse an incoming AuthnRequest."""
    try:
        decoded = OneLogin_Saml2_Utils.decode_base64_and_inflate(saml_request_b64)
        root = etree.fromstring(decoded)

        request_id = root.get("ID")
        issuer_elem = root.find("{urn:oasis:names:tc:SAML:2.0:assertion}Issuer")
        issuer = issuer_elem.text if issuer_elem is not None else None
        acs_url = root.get("AssertionConsumerServiceURL")

        return {
            "id": request_id,
            "issuer": issuer,
            "acs_url": acs_url,
        }
    except Exception as e:
        print(f"Error parsing AuthnRequest: {e}")
        return None


