class SAMLIdPHandler(BaseHTTPRequestHandler):
    """HTTP Request Handler for the SAML IdP."""

    def do_GET(self):
        """Handle GET requests."""
        path = self.path.split("?")[0]

        if path == "/metadata":
            self.handle_metadata()
        elif path == "/sso":
            self.handle_sso_get()
        elif path == "/slo":
            self.handle_slo()
        elif path == "/":
            self.handle_index()
        else:
            self.send_error(404)

    def do_POST(self):
        """Handle POST requests."""
        path = self.path.split("?")[0]

        if path == "/sso":
            self.handle_sso_post()
        elif path == "/slo":
            self.handle_slo_post()
        else:
            self.send_error(404)

    def handle_index(self):
        """Serve the index page."""
        html = """<!DOCTYPE html>
<html>
<head><title>Internal SAML IdP</title>
<style>
    body { font-family: Arial, sans-serif; max-width: 800px; margin: 50px auto; padding: 20px; }
    h1 { color: #333; }
    a { color: #0066cc; }
    .endpoint { background: #f5f5f5; padding: 15px; margin: 10px 0; border-radius: 4px; }
    code { background: #eee; padding: 2px 6px; border-radius: 3px; }
</style>
</head>
<body>
    <h1>🔐 Internal SAML Identity Provider</h1>
    <p>This is an internal SAML 2.0 Identity Provider.</p>
    <h2>Endpoints</h2>
    <div class="endpoint">
        <strong>Metadata:</strong> <a href="/metadata">/metadata</a>
    </div>
    <div class="endpoint">
        <strong>SSO (Single Sign-On):</strong> <code>/sso</code>
    </div>
    <div class="endpoint">
        <strong>SLO (Single Logout):</strong> <code>/slo</code>
    </div>
    <h2>IdP-Initiated SSO</h2>
    <p>For testing, you can initiate SSO directly:</p>"""

        for sp_id, sp_info in SP_REGISTRY.items():
            html += f'<div class="endpoint"><a href="/sso?sp_entity_id={quote(sp_id)}">{sp_info["name"]}</a> ({sp_id})</div>'

        html += """
</body>
</html>"""
        self.send_html_response(200, html)

    def handle_metadata(self):
        """Serve IdP metadata."""
        metadata = generate_idp_metadata()
        self.send_response(200)
        self.send_header("Content-Type", "application/xml")
        self.send_header("Cache-Control", "no-cache, no-store")
        self.end_headers()
        self.wfile.write(metadata.encode("utf-8"))

    def handle_sso_get(self):
        """Handle SSO via HTTP-Redirect binding."""
        query_string = self.path.split("?", 1)[1] if "?" in self.path else ""
        params = parse_qs(query_string)

        saml_request = params.get("SAMLRequest", [None])[0]
        relay_state = params.get("RelayState", [None])[0]
        sp_entity_id = params.get("sp_entity_id", [None])[0]

        authn_request_id = None
        acs_url = None

        if saml_request:
            # SP-initiated SSO
            parsed_request = parse_authn_request(saml_request)
            if parsed_request:
                authn_request_id = parsed_request["id"]
                sp_entity_id = parsed_request["issuer"]
                acs_url = parsed_request.get("acs_url")

        # Validate SP
        if sp_entity_id and sp_entity_id not in SP_REGISTRY:
            self.send_html_response(400, "<h1>Error: Unknown Service Provider</h1>")
            return

        # Check for existing session
        session_id = self.get_cookie("idp_session")
        session = get_session(session_id)

        if session:
            # User already authenticated, generate SAML response
            self.complete_sso(
                sp_entity_id=sp_entity_id,
                acs_url=acs_url,
                user_attributes=session["attributes"],
                relay_state=relay_state,
                authn_request_id=authn_request_id,
            )
        else:
            # Show login form
            login_page = generate_login_page(
                sp_entity_id=sp_entity_id,
                relay_state=relay_state,
                authn_request_id=authn_request_id,
            )
            self.send_html_response(200, login_page)

    def handle_sso_post(self):
        """Handle SSO login form submission."""
        content_length = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(content_length).decode("utf-8")
        params = parse_qs(body)

        username = params.get("username", [None])[0]
        password = params.get("password", [None])[0]
        sp_entity_id = params.get("sp_entity_id", [None])[0]
        relay_state = params.get("relay_state", [None])[0]
        authn_request_id = params.get("authn_request_id", [None])[0]

        if not username or not password:
            login_page = generate_login_page(
                sp_entity_id=sp_entity_id,
                relay_state=relay_state,
                authn_request_id=authn_request_id,
                error_message="Username and password are required.",
            )
            self.send_html_response(400, login_page)
            return

        # Authenticate
        user_attributes = authenticate_user(username, password)

        if not user_attributes:
            login_page = generate_login_page(
                sp_entity_id=sp_entity_id,
                relay_state=relay_state,
                authn_request_id=authn_request_id,
                error_message="Invalid username or password.",
            )
            self.send_html_response(401, login_page)
            return

        # Create session
        session_id = create_session(username, user_attributes)

        # If no SP specified, show success page
        if not sp_entity_id:
            self.send_response(200)
            self.send_header("Content-Type", "text/html")
            self.send_header(
                "Set-Cookie",
                f"idp_session={session_id}; Path=/; Secure; HttpOnly; SameSite=None",
            )
            self.end_headers()
            html = f"""<!DOCTYPE html>
<html><head><title>Login Successful</title></head>
<body style="font-family: Arial; text-align: center; padding-top: 50px;">
<h1>✅ Login Successful</h1>
<p>Welcome, {user_attributes.get('firstName', username)}!</p>
<p>You are now authenticated with the IdP.</p>
</body></html>"""
            self.wfile.write(html.encode("utf-8"))
            return

        # Complete SSO flow
        self.send_response(200)
        self.send_header("Content-Type", "text/html")
        self.send_header(
            "Set-Cookie",
            f"idp_session={session_id}; Path=/; Secure; HttpOnly; SameSite=None",
        )
        self.end_headers()

        acs_url = None  # Will be resolved from SP registry
        response_html = self.build_sso_response(
            sp_entity_id=sp_entity_id,
            acs_url=acs_url,
            user_attributes=user_attributes,
            relay_state=relay_state,
            authn_request_id=authn_request_id,
        )
        self.wfile.write(response_html.encode("utf-8"))

    def complete_sso(self, sp_entity_id, acs_url, user_attributes, relay_state, authn_request_id):
        """Complete the SSO flow by generating and sending a SAML response."""
        response_html = self.build_sso_response(
            sp_entity_id=sp_entity_id,
            acs_url=acs_url,
            user_attributes=user_attributes,
            relay_state=relay_state,
            authn_request_id=authn_request_id,
        )
        self.send_html_response(200, response_html)

    def build_sso_response(self, sp_entity_id, acs_url, user_attributes, relay_state, authn_request_id):
        """Build the SSO response HTML with signed SAML assertion."""
        # Resolve ACS URL from SP registry if not provided
        if not acs_url and sp_entity_id in SP_REGISTRY:
            acs_url = SP_REGISTRY[sp_entity_id]["acs_url"]

        if not acs_url:
            return "<h1>Error: Cannot determine Assertion Consumer Service URL</h1>"

        # Build SAML Response (signed, not encrypted)
        saml_response_xml = build_saml_response(
            sp_entity_id=sp_entity_id,
            acs_url=acs_url,
            user_attributes=user_attributes,
            authn_request_id=authn_request_id,
        )

        # Base64 encode the response
        saml_response_b64 = OneLogin_Saml2_Utils.b64encode(saml_response_xml)

        # Generate POST binding form
        return generate_post_binding_form(acs_url, saml_response_b64, relay_state)

    def handle_slo(self):
        """Handle Single Logout via GET (HTTP-Redirect binding)."""
        session_id = self.get_cookie("idp_session")
        destroy_session(session_id)

        query_string = self.path.split("?", 1)[1] if "?" in self.path else ""
        params = parse_qs(query_string)
        relay_state = params.get("RelayState", [None])[0]

        self.send_response(200)
        self.send_header("Content-Type", "text/html")
        self.send_header(
            "Set-Cookie",
            "idp_session=; Path=/; Secure; HttpOnly; SameSite=None; Max-Age=0",
        )
        self.end_headers()

        html = """<!DOCTYPE html>
<html><head><title>Logged Out</title></head>
<body style="font-family: Arial; text-align: center; padding-top: 50px;">
<h1>👋 Logged Out</h1>
<p>You have been successfully logged out.</p>
<a href="/">Return to IdP</a>
</body></html>"""
        self.wfile.write(html.encode("utf-8"))

    def handle_slo_post(self):
        """Handle SLO via POST."""
        self.handle_slo()

    def get_cookie(self, name):
        """Extract a cookie value from the request."""
        cookie_header = self.headers.get("Cookie", "")
        cookies = {}
        for item in cookie_header.split(";"):
            item = item.strip()
            if "=" in item:
                key, value = item.split("=", 1)
                cookies[key.strip()] = value.strip()
        return cookies.get(name)

    def send_html_response(self, status_code, html):
        """Send an HTML response."""
        self.send_response(status_code)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Cache-Control", "no-cache, no-store, must-revalidate")
        self.send_header("Pragma", "no-cache")
        self.send_header("X-Content-Type-Options", "nosniff")
        self.send_header("X-Frame-Options", "DENY")
        self.send_header(
            "Strict-Transport-Security", "max-age=31536000; includeSubDomains"
        )
        self.end_headers()
        self.wfile.write(html.encode("utf-8"))

    def log_message(self, format, *args):
        """Custom log format."""
        print(
            f"[{datetime.now(timezone.utc).isoformat()}] {self.client_address[0]} - {format % args}"
        )


def run_idp_server():
    """Start the SAML IdP server with HTTPS."""
    generate_certificates()

    host = IDP_CONFIG["host"]
    port = IDP_CONFIG["port"]

    server = HTTPServer((host, port), SAMLIdPHandler)

    # Configure SSL/TLS
    ssl_context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    ssl_context.minimum_version = ssl.TLSVersion.TLSv1_2
    ssl_context.load_cert_chain(
        certfile=IDP_CONFIG["ssl_cert_file"],
        keyfile=IDP_CONFIG["ssl_key_file"],
    )
    # Disable weak ciphers
    ssl_context.set_ciphers(
        "ECDHE+AESGCM:ECDHE+CHACHA20:DHE+AESGCM:DHE+CHACHA20:!aNULL:!MD5:!DSS"
    )

    server.socket = ssl_context.wrap_socket(server.socket, server_side=True)

    print(f"=" * 60)
    print(f"  Internal SAML Identity Provider")
    print(f"  Running on https://{host}:{port}")
    print(f"  Metadata: https://{host}:{port}/metadata")
    print(f"  SSO URL:  https://{host}:{port}/sso")
    print(f"  SLO URL:  https://{host}:{port}/slo")
    print(f"=" * 60)
    print(f"\nRegistered Service Providers:")
    for sp_id, sp_info in SP_REGISTRY.items():
        print(f"  - {sp_info['name']} ({sp_id})")
    print(f"\nAvailable test users:")
    for username in USER_STORE:
        print(f"  - {username}")
    print(f"\nNote: Assertions are signed but NOT encrypted.")
    print(f"Transport security is provided by HTTPS (TLS 1.2+).")
    print(f"\nServer started. Press Ctrl+C to stop.\n")

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nShutting down IdP server...")
        server.shutdown()


if __name__ == "__main__":
    run_idp_server()